<template>
  <div class="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 flex items-center justify-center p-4">
    <div class="max-w-6xl w-full">
      <!-- Header -->
      <div class="text-center mb-8">
        <h1 class="text-4xl font-bold text-gray-900 mb-4">
          Khanal Foods Kiosk
        </h1>
        <p class="text-xl text-gray-600">
          Select your plant to continue
        </p>
      </div>

      <!-- Loading / Error / Empty States -->
      <div v-if="loading" class="flex items-center justify-center py-16">
        <div class="flex items-center space-x-3 text-gray-600">
          <svg class="animate-spin h-5 w-5 text-blue-600" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"></circle>
            <path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"></path>
          </svg>
          <span>Loading plants...</span>
        </div>
      </div>

      <div v-else-if="error" class="bg-red-50 border border-red-200 text-red-700 p-4 rounded mb-6">
        {{ error }}
      </div>

      <div v-else-if="!plants.length" class="bg-yellow-50 border border-yellow-200 text-yellow-800 p-4 rounded mb-6">
        No plants available. Please contact the administrator.
      </div>

      <!-- Plant Selection Grid -->
      <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        <div
          v-for="plant in plants"
          :key="plant.id"
          @click="selectPlant(plant)"
          class="bg-white rounded-xl shadow-lg hover:shadow-xl transition-all duration-300 cursor-pointer transform hover:scale-105 border-2 border-transparent hover:border-blue-200"
        >
          <!-- Plant Image -->
          <div class="h-48 bg-gradient-to-br from-blue-400 to-blue-600 rounded-t-xl flex items-center justify-center">
            <div class="text-white text-6xl">
              {{ plant.icon }}
            </div>
          </div>

          <!-- Plant Info -->
          <div class="p-6">
            <h3 class="text-2xl font-bold text-gray-900 mb-2">
              {{ plant.name }}
            </h3>
            <p class="text-gray-600 mb-4">
              {{ plant.location }}
            </p>
            
            <!-- Plant Type Badge -->
            <div class="flex items-center mb-4">
              <span class="inline-flex items-center px-3 py-1 rounded-full text-sm font-medium"
                    :class="getPlantTypeClass(plant.type)">
                {{ plant.type }}
              </span>
            </div>

            <!-- Plant Details -->
            <div class="space-y-2 text-sm text-gray-600">
              <div class="flex items-center">
                <svg class="w-4 h-4 mr-2 text-blue-500" fill="currentColor" viewBox="0 0 20 20">
                  <path fill-rule="evenodd" d="M5.05 4.05a7 7 0 119.9 9.9L10 18.9l-4.95-4.95a7 7 0 010-9.9zM10 11a2 2 0 100-4 2 2 0 000 4z" clip-rule="evenodd" />
                </svg>
                {{ plant.location }}
              </div>
              <div class="flex items-center">
                <svg class="w-4 h-4 mr-2 text-green-500" fill="currentColor" viewBox="0 0 20 20">
                  <path fill-rule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm1-12a1 1 0 10-2 0v4a1 1 0 00.293.707l2.828 2.829a1 1 0 101.415-1.415L11 9.586V6z" clip-rule="evenodd" />
