</template>

<script setup>
import { ref, onMounted } from 'vue'
import { useRouter } from 'vue-router'
import { useActivityLogger } from '@/core/utils/activityLogger.js'
import { plantService } from '@/core/api/plantService.js'
import { APP_CONFIG } from '@/config/constants.js'

// Composables
const router = useRouter()
const activityLogger = useActivityLogger()

// Reactive data
const plants = ref([])
const loading = ref(true)
const error = ref('')
const selectedPlantId = ref(null)

// Local fallback in case API fails hard
const fallbackPlantData = []

// Methods
function getPlantTypeClass(type) {
  const classes = {
    'Primary Production Facility': 'bg-blue-100 text-blue-800',
    'Mountain Operations': 'bg-green-100 text-green-800',
    'Regional Operations': 'bg-yellow-100 text-yellow-800',
    'Cross-Border Operations': 'bg-purple-100 text-purple-800',
    'R&D Center': 'bg-indigo-100 text-indigo-800'
  }
  return classes[type] || 'bg-gray-100 text-gray-800'
}

async function selectPlant(plant) {
  if (loading.value) return
  
  loading.value = true
  selectedPlantId.value = plant.id

  // Ensure we have a safe slug to use in the route even if names/ids changed
  const slug = String(plant.id || plant.name || '')
    .toLowerCase()
    .trim()
    .replace(/\s+/g, '-')
    .replace(/[^a-z0-9-_]/g, '')

  try {
    // Store selected plant for later use
    sessionStorage.setItem('selected-plant', JSON.stringify({ ...plant, id: slug }))

    // Navigate first to avoid blocking on any async logging
    router.push(`/login/${slug}`)

    // Fire-and-forget activity logging
    activityLogger.logActivity({
      type: 'plant_selection',
      action: 'select_plant',
      metadata: {
        plant_id: slug,
        original_id: plant.id,
        plant_name: plant.name,
        plant_type: plant.type,
        user_agent: navigator.userAgent
      }
    }).catch(() => {})
  } catch (error) {
    console.error('Error selecting plant:', error)
    try {
      await activityLogger.logError(error, {
        action: 'plant_selection',
        plant_id: slug
      })
    } catch {}
  } finally {
    loading.value = false
    selectedPlantId.value = null
  }
}

// Load plants from Frappe backend
async function loadPlants() {
  try {
    loading.value = true
    error.value = ''
    
    // Fetch from backend
    const cacheKey = 'kiosk_plants_cache'
    const cached = sessionStorage.getItem(cacheKey)
    if (cached) {
      try { plants.value = JSON.parse(cached) } catch {}
    }

    const apiPlants = await plantService.getPlants()
    if (Array.isArray(apiPlants) && apiPlants.length) {
      plants.value = apiPlants
      sessionStorage.setItem(cacheKey, JSON.stringify(apiPlants))
    } else if (!plants.value.length) {
      plants.value = fallbackPlantData
    }
    
  } catch (err) {
    console.error('Error loading plants:', err)
    error.value = 'Failed to load plants. Using default data.'
    // Fallback to cache or empty
    const cacheKey = 'kiosk_plants_cache'
    const cached = sessionStorage.getItem(cacheKey)
    if (cached) {
      try { plants.value = JSON.parse(cached) } catch { plants.value = fallbackPlantData }
    } else {
      plants.value = fallbackPlantData
    }
  } finally {
    loading.value = false
  }
}

// Lifecycle
onMounted(async () => {
  await loadPlants()
  
  // Log page view
  activityLogger.logPageView('/plant-selection')
})
</script>

